#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        // Error occurred
        perror("fork failed");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child: PID = %d, Parent PID = %d\n", getpid(), getppid());

        // Replace child program with new executable
        execl("/bin/ls", "ls", "-l", NULL);

        // If exec fails
        perror("exec failed");
        _exit(1);
    }
    else {
        // Parent process
        printf("Parent: Child PID = %d\n", pid);

        // Wait for child to complete
        int status;
        waitpid(pid, &status, 0);
        printf("Child terminated\n");
    }

    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <string.h>
#include <sys/wait.h>

int main() {
    int pipefd[2];
    char write_msg[] = "Message from parent";
    char read_msg[50];

    // Create pipe (system call: pipe)
    if (pipe(pipefd) == -1) {
        perror("pipe failed");
        return 1;
    }

    pid_t pid = fork();

    if (pid == 0) {
        // Child process - reads from pipe
        close(pipefd[1]); // Close write end
        read(pipefd[0], read_msg, sizeof(read_msg));
        printf("Child received: %s\n", read_msg);
        close(pipefd[0]);
    }
    else {
        // Parent process - writes to pipe
        close(pipefd[0]); // Close read end
        write(pipefd[1], write_msg, strlen(write_msg) + 1);
        close(pipefd[1]);
        wait(NULL); // Wait for child
    }

    return 0;
}

// USER SPACE CODE
FUNCTION user_read(fileDescriptor, buffer, count)
BEGIN
    // 1. Load system call number in EAX (read = 3)
    EAX = 3

    // 2. Load parameters in registers
    EBX = fileDescriptor  // first parameter
    ECX = buffer          // second parameter
    EDX = count           // third parameter

    // 3. Trigger trap to enter kernel mode
    TRAP 0x80  // software interrupt

    // 4. Return value in EAX
    RETURN EAX
END

// KERNEL SPACE CODE (System Call Handler)
FUNCTION sys_read(fileDescriptor, buffer, count)
BEGIN
    // Validate file descriptor
    IF NOT valid(fileDescriptor) THEN
        RETURN -EBADF  // error: bad file descriptor
    ENDIF

    // Check user buffer accessibility
    IF NOT accessible(buffer) THEN
        RETURN -EFAULT  // error: bad address
    ENDIF

    // Perform the read operation
    bytesRead = perform_read(fileDescriptor, buffer, count)

    // Return to user mode with result
    RETURN bytesRead
END
